import{_ as t,c as o,o as s,ag as n}from"./chunks/framework.C_7JoTpM.js";const a="/2025-Team-Epibot-Docs/images/electro/their_exemple.png",i="/2025-Team-Epibot-Docs/images/electro/Face_and_segments_after_montage.jpg",r="/2025-Team-Epibot-Docs/images/electro/rounded_border.png",l="/2025-Team-Epibot-Docs/images/electro/mechanismes_inspiration.png",c="/2025-Team-Epibot-Docs/images/electro/differents_part_bracket.png",p="/2025-Team-Epibot-Docs/images/electro/segment_parts.png",g="/2025-Team-Epibot-Docs/images/electro/slicing_1.png",h="/2025-Team-Epibot-Docs/images/electro/slicing_2.png",d="/2025-Team-Epibot-Docs/images/electro/Step_2_assembly.jpg",m="/2025-Team-Epibot-Docs/images/electro/laser_cutting.jpg",u="/2025-Team-Epibot-Docs/images/electro/laser_cutting_2.jpg",b="/2025-Team-Epibot-Docs/images/electro/face_avant.png",D=JSON.parse('{"title":"Documentation for the Realization of the 7-Segment Servo Display Mechanism","description":"","frontmatter":{},"headers":[],"relativePath":"week3/pole-electronic/seven_digit_doc.md","filePath":"week3/pole-electronic/seven_digit_doc.md"}'),f={name:"week3/pole-electronic/seven_digit_doc.md"};function y(_,e,q,v,F,w){return s(),o("div",null,e[0]||(e[0]=[n('<h1 id="documentation-for-the-realization-of-the-7-segment-servo-display-mechanism" tabindex="-1"><strong><span style="color:#2E86C1;">Documentation for the Realization of the 7-Segment Servo Display Mechanism</span></strong> <a class="header-anchor" href="#documentation-for-the-realization-of-the-7-segment-servo-display-mechanism" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #2E86C1;&quot;&gt;Documentation for the Realization of the 7-Segment Servo Display Mechanism&lt;/span&gt;**&quot;">​</a></h1><h2 id="introduction" tabindex="-1"><strong><span style="color:#FF69B4;">Introduction</span></strong> <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #FF69B4;&quot;&gt;Introduction&lt;/span&gt;**&quot;">​</a></h2><p>This project focuses on designing and building the physical body of a <strong>7-segment servo display</strong>. Unlike traditional designs, we aimed for an innovative and functional approach by adopting a <strong>vertical configuration</strong> inspired by the principles of mechanical engineering, particularly the operation of hydraulic cylinders (or &quot;vérins&quot;). Our goal was to create a unique display that combines functionality with aesthetic appeal, leveraging inspiration from open-source projects such as:</p><ul><li><a href="https://www.instructables.com/Kinetic-Digital-Clock-Arduino-3D-Print/" target="_blank" rel="noreferrer">Kinetic Digital Clock Arduino 3D Print</a></li><li><a href="https://www.instructables.com/Digital-Analog-Clock-With-Stepper-Motors/" target="_blank" rel="noreferrer">Digital Analog Clock With Stepper Motors</a></li></ul><p>In the following sections, we document the entire process, including analysis, design, fabrication, assembly, and testing.</p><hr><h2 id="step-1-analysis" tabindex="-1"><strong><span style="color:#2E86C1;">Step 1: Analysis</span></strong> <a class="header-anchor" href="#step-1-analysis" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #2E86C1;&quot;&gt;Step 1: Analysis&lt;/span&gt;**&quot;">​</a></h2><h3 id="innovative-design-choices" tabindex="-1"><strong><span style="color:#FF69B4;">Innovative Design Choices</span></strong> <a class="header-anchor" href="#innovative-design-choices" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #FF69B4;&quot;&gt;Innovative Design Choices&lt;/span&gt;**&quot;">​</a></h3><p>The first challenge we set for ourselves was to mount the display in a <strong><code>vertical format</code></strong>, deviating from the traditional horrizontal layout. This decision was driven by our desire for a compact and visually appealing design.</p><p><strong>Illustrating version</strong><img src="'+a+'" alt="Final Design vs Original Example"></p><p><img src="'+i+'" alt=""></p><p>Additionally, we wanted to avoid sharp edges, opting instead for <strong><code>rounded borders</code></strong> to give the display a sleek and modern appearance.</p><p><img src="'+r+'" alt="Rounded Borders vs Original"></p><h3 id="mechanism-design" tabindex="-1"><strong><span style="color:#FF69B4;">Mechanism Design</span></strong> <a class="header-anchor" href="#mechanism-design" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #FF69B4;&quot;&gt;Mechanism Design&lt;/span&gt;**&quot;">​</a></h3><p>For the internal mechanism, we drew inspiration from the open-source project <a href="https://www.instructables.com/Kinetic-Digital-Clock-Arduino-3D-Print/" target="_blank" rel="noreferrer">Kinetic Digital Clock Arduino 3D Print</a>, particularly its <strong><code>gear system</code></strong>. This inspired us to recreate our own mechanism tailored to meet the specific requirements of this project.</p><p><img src="'+l+'" alt="Mechanism Inspiration"></p><p>The core idea is to use <strong><code>servo motors</code></strong> to drive gears, converting rotational motion into linear motion for each segment. Below is a screenshot of a segment in motion:</p><hr><h3 id="etapes-d-assemblage" tabindex="-1"><strong><span style="color:#FF69B4;">Etapes d&#39;assemblage</span></strong> <a class="header-anchor" href="#etapes-d-assemblage" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #FF69B4;&quot;&gt;Etapes d&#39;assemblage&lt;/span&gt;**&quot;">​</a></h3><h2 id="step-2-component-design" tabindex="-1"><strong><span style="color:#2E86C1;">Step 2: Component Design</span></strong> <a class="header-anchor" href="#step-2-component-design" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #2E86C1;&quot;&gt;Step 2: Component Design&lt;/span&gt;**&quot;">​</a></h2><p>Using <strong><code>SolidWorks</code></strong>, <strong><code>Fusion 360</code></strong>, and <strong><code>PrusaSlicer</code></strong>, we modeled and fabricated each component of the display. Below are the details of the key parts:</p><h3 id="_1-bracket-assembly" tabindex="-1"><strong><span style="color:#FF69B4;">1. Bracket Assembly</span></strong> <a class="header-anchor" href="#_1-bracket-assembly" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #FF69B4;&quot;&gt;1. Bracket Assembly&lt;/span&gt;**&quot;">​</a></h3><p>The bracket serves as the backbone of the mechanism:</p><ul><li>It holds the servo motor vertically and connects it to the gear system.</li><li>On one side, it is fixed at a <strong><code>90° angle</code></strong> to support the longitudinal part of the segment.</li><li>The bracket ensures precise alignment and smooth movement of the segments.</li></ul><p><img src="'+c+'" alt="Bracket Components"></p><h3 id="_2-segment" tabindex="-1"><strong><span style="color:#FF69B4;">2. Segment</span></strong> <a class="header-anchor" href="#_2-segment" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #FF69B4;&quot;&gt;2. Segment&lt;/span&gt;**&quot;">​</a></h3><p>The segment is the visible part of the display and consists of two parts:</p><ol><li><strong>Head</strong>: The surface seen by the user, featuring rounded edges for aesthetic appeal.</li><li><strong>Body</strong>: The hidden, toothed portion that interacts with the gear system.</li></ol><p><img src="'+p+'" alt="Segment Components"></p><hr><h2 id="step-3-fabrication" tabindex="-1"><strong><span style="color:#2E86C1;">Step 3: Fabrication</span></strong> <a class="header-anchor" href="#step-3-fabrication" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #2E86C1;&quot;&gt;Step 3: Fabrication&lt;/span&gt;**&quot;">​</a></h2><h3 id="_3d-printing" tabindex="-1"><strong><span style="color:#FF69B4;">3D Printing</span></strong> <a class="header-anchor" href="#_3d-printing" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #FF69B4;&quot;&gt;3D Printing&lt;/span&gt;**&quot;">​</a></h3><p>Once the design was complete, we proceeded to fabricate the components using <strong>3D printing</strong>. Below are the steps involved:</p><ol><li><p><strong><span style="color:#FF69B4;">Slicing the Models</span></strong></p><ul><li>We used <strong>PrusaSlicer</strong> to prepare the models for 3D printing.</li><li>Settings included a layer height of 0.2 mm, 20% infill, and support structures where necessary.</li></ul><p><img src="'+g+'" alt="Slicing Process"><img src="'+h+'" alt="Slicing Process"></p></li><li><p><strong><span style="color:#FF69B4;">Printing</span></strong></p><ul><li>The components were printed using PLA filament for its ease of use and durability.</li><li>Total printing time for all parts was approximately <strong>7 hours</strong>.</li></ul></li></ol><hr><h2 id="step-4-assembly" tabindex="-1"><strong><span style="color:#2E86C1;">Step 4: Assembly</span></strong> <a class="header-anchor" href="#step-4-assembly" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #2E86C1;&quot;&gt;Step 4: Assembly&lt;/span&gt;**&quot;">​</a></h2><h3 id="process-overview" tabindex="-1"><strong><span style="color:#FF69B4;">Process Overview</span></strong> <a class="header-anchor" href="#process-overview" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #FF69B4;&quot;&gt;Process Overview&lt;/span&gt;**&quot;">​</a></h3><p>The assembly process involved combining all the fabricated components into a fully functional display. Below are the key steps:</p><ol><li><p><strong><span style="color:#FF69B4;">Attaching Segments to Gears</span></strong></p><ul><li>Each segment was attached to its respective gear using the toothed body. This connection ensures precise control over the segment&#39;s movement.</li></ul></li><li><p><strong><span style="color:#FF69B4;">Mounting Servos to the Frame</span></strong></p><ul><li>The servos were mounted onto the bracket assembly using screws or adhesive mounts. Proper alignment was critical to ensure smooth operation.</li></ul><p><a href="/2025-Team-Epibot-Docs/images/electro/Step_1_assembly.mp4">Slicing Process</a></p><p><img src="'+d+'" alt="Slicing Process"></p><p><img src="'+m+'" alt="Slicing Process"></p><p><img src="'+u+'" alt="Slicing Process"></p></li></ol><hr><h2 id="step-5-enclosure-design" tabindex="-1"><strong><span style="color:#2E86C1;">Step 5: Enclosure Design</span></strong> <a class="header-anchor" href="#step-5-enclosure-design" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #2E86C1;&quot;&gt;Step 5: Enclosure Design&lt;/span&gt;**&quot;">​</a></h2><h3 id="vision" tabindex="-1"><strong><span style="color:#FF69B4;">Vision</span></strong> <a class="header-anchor" href="#vision" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #FF69B4;&quot;&gt;Vision&lt;/span&gt;**&quot;">​</a></h3><p>Our vision for the enclosure was to create a <strong>two-tiered container</strong>:</p><ul><li><strong>Top Tier</strong>: Houses the servo motors.</li><li><strong>Bottom Tier</strong>: Contains the electronic circuitry.</li></ul><h3 id="front-face" tabindex="-1"><strong><span style="color:#FF69B4;">Front Face</span></strong> <a class="header-anchor" href="#front-face" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #FF69B4;&quot;&gt;Front Face&lt;/span&gt;**&quot;">​</a></h3><p>The front face contains hollow cavities shaped like the number &quot;8,&quot; through which the segments slide to display digits. This part is critical for ensuring proper alignment and visibility of the segments.</p><p><img src="'+b+'" alt="Front Face Design"></p><hr><h2 id="conclusion" tabindex="-1"><strong><span style="color:#2E86C1;">Conclusion</span></strong> <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;**&lt;span style=&quot;color: #2E86C1;&quot;&gt;Conclusion&lt;/span&gt;**&quot;">​</a></h2><p>This documentation outlines the step-by-step process of designing, fabricating, and assembling the 7-segment servo display. By combining innovative design choices with precise engineering, we created a functional and visually appealing mechanism. This project demonstrates our ability to think creatively while adhering to technical constraints.</p>',50)]))}const S=t(f,[["render",y]]);export{D as __pageData,S as default};
